import React from 'react';
import { BrowserRouter, Routes, Route, NavLink } from 'react-router-dom';
import LeadsPage from './pages/LeadsPage';
import MonitorPage from './pages/MonitorPage';
import BotPage from './pages/BotPage';
import SendPage from './pages/SendPage';

const nav = [
  { to: '/', label: 'Leads' },
  { to: '/monitor', label: 'Monitoring' },
  { to: '/bot', label: 'Bot' },
  { to: '/send', label: 'Envoi' },
];

export default function App() {
  return (
    <BrowserRouter>
      <div className="min-h-screen flex flex-col">
        <header className="bg-gray-900 border-b border-gray-800 px-6 py-4 flex items-center gap-8">
          <span className="text-xl font-bold text-indigo-400">🤖 Lead Bot</span>
          <nav className="flex gap-4">
            {nav.map(({ to, label }) => (
              <NavLink
                key={to}
                to={to}
                end={to === '/'}
                className={({ isActive }) =>
                  `px-3 py-1.5 rounded text-sm font-medium transition ${
                    isActive ? 'bg-indigo-600 text-white' : 'text-gray-400 hover:text-white'
                  }`
                }
              >
                {label}
              </NavLink>
            ))}
          </nav>
        </header>
        <main className="flex-1 p-6">
          <Routes>
            <Route path="/" element={<LeadsPage />} />
            <Route path="/monitor" element={<MonitorPage />} />
            <Route path="/bot" element={<BotPage />} />
            <Route path="/send" element={<SendPage />} />
          </Routes>
        </main>
      </div>
    </BrowserRouter>
  );
}
